mapper.insert:

    SELECT 'ORD-' || TO_CHAR(SYSDATE, 'YYYYMMDD-') || LPAD(SEQ_ORDERS_PK.NEXTVAL, 6, '0’)
      FROM DUAL

INSERT INTO ORDERS 
 (ORDER_ID
 , ITEM_ID
 , ITEM_ORDER_COUNT
 , ITEM_UNIT_PRICE
 , ORDER_AMOUNT_PRICE
 , USER_ID
 , CREATE_AT) 
VALUES
 (#{orderId}
, #{itemId}
, #{itemOrderCount}
, #{itemUnitPrice}
, #{itemUnitPrice} * #{itemOrderCount}
, #{userId}
, SYSDATE)
